using ContosoUniversity.Models;
using ContosoUniversity.Services;
using System;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain any leftover notifications from other tests (static queue)
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_CreatesNotification_WithCorrectProperties()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
            Assert.Null(notification.ReadAt);
        }

        [Fact]
        public void SendNotification_CreateOperation_GeneratesCorrectMessage_WithDisplayName()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("New Student 'John Doe' has been created", notification.Message);
        }

        [Fact]
        public void SendNotification_UpdateOperation_GeneratesCorrectMessage_WithDisplayName()
        {
            _service.SendNotification("Course", "1050", "Chemistry", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Course 'Chemistry' has been updated", notification.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_GeneratesCorrectMessage_WithDisplayName()
        {
            _service.SendNotification("Department", "1", "Engineering", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Department 'Engineering' has been deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("New Student (ID: 42) has been created", notification.Message);
        }

        [Fact]
        public void SendNotification_NullDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Student", "42", null, EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student (ID: 42) has been updated", notification.Message);
        }

        [Fact]
        public void SendNotification_EmptyDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Student", "42", "  ", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student (ID: 42) has been deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_DefaultUserName_IsSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now.AddSeconds(-1);
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now.AddSeconds(1);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void ReceiveNotification_ReturnsNull_WhenQueueIsEmpty()
        {
            var notification = _service.ReceiveNotification();
            Assert.Null(notification);
        }

        [Fact]
        public void ReceiveNotification_ReturnsNotificationsInOrder()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            _service.SendNotification("Course", "2", EntityOperation.UPDATE);
            _service.SendNotification("Department", "3", EntityOperation.DELETE);

            var n1 = _service.ReceiveNotification();
            var n2 = _service.ReceiveNotification();
            var n3 = _service.ReceiveNotification();
            var n4 = _service.ReceiveNotification();

            Assert.Equal("Student", n1!.EntityType);
            Assert.Equal("Course", n2!.EntityType);
            Assert.Equal("Department", n3!.EntityType);
            Assert.Null(n4);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op for in-memory implementation
            var ex = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(ex);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var ex = Record.Exception(() => service.Dispose());
            Assert.Null(ex);
        }

        [Fact]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            var service = new NotificationService();
            service.Dispose();
            var ex = Record.Exception(() => service.Dispose());
            Assert.Null(ex);
        }
    }
}

using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndex()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 2, 3);
            Assert.Equal(2, list.PageIndex);
        }

        [Fact]
        public void Constructor_CalculatesTotalPages()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 1, 3);
            Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
        }

        [Fact]
        public void Constructor_CalculatesTotalPages_ExactDivision()
        {
            var items = new List<int> { 1, 2 };
            var list = new PaginatedList<int>(items, 10, 1, 5);
            Assert.Equal(2, list.TotalPages); // ceil(10/5) = 2
        }

        [Fact]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<string> { "a", "b", "c" };
            var list = new PaginatedList<string>(items, 3, 1, 3);
            Assert.Equal(3, list.Count);
            Assert.Contains("a", list);
            Assert.Contains("b", list);
            Assert.Contains("c", list);
        }

        [Fact]
        public void HasPreviousPage_ReturnsFalse_WhenOnFirstPage()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 5, 1, 3);
            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_ReturnsTrue_WhenNotOnFirstPage()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 5, 2, 3);
            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_ReturnsTrue_WhenNotOnLastPage()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 3);
            Assert.True(list.HasNextPage); // totalPages = 4, page 1 < 4
        }

        [Fact]
        public void HasNextPage_ReturnsFalse_WhenOnLastPage()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 4, 3);
            Assert.False(list.HasNextPage); // totalPages = 4, page 4 is not < 4
        }

        [Fact]
        public void HasNextPage_ReturnsFalse_WhenSinglePage()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 1, 1, 10);
            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();
            var result = PaginatedList<int>.Create(source, 2, 5);

            Assert.Equal(2, result.PageIndex);
            Assert.Equal(4, result.TotalPages);
            Assert.Equal(5, result.Count);
            Assert.Equal(6, result[0]); // items 6-10 on page 2
            Assert.Equal(10, result[4]);
        }

        [Fact]
        public void Create_FirstPage_ReturnsFirstItems()
        {
            var source = Enumerable.Range(1, 15).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Equal(1, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
            Assert.Equal(5, result.Count);
            Assert.Equal(1, result[0]);
        }

        [Fact]
        public void Create_LastPage_ReturnRemainingItems()
        {
            var source = Enumerable.Range(1, 12).AsQueryable();
            var result = PaginatedList<int>.Create(source, 3, 5);

            Assert.Equal(3, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
            Assert.Equal(2, result.Count); // only 2 remaining items
            Assert.Equal(11, result[0]);
            Assert.Equal(12, result[1]);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = new List<int>().AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Empty(result);
            Assert.Equal(0, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }
    }
}

