using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndex()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 2, 3);
            Assert.Equal(2, list.PageIndex);
        }

        [Fact]
        public void Constructor_CalculatesTotalPages()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 10, 1, 3);
            Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
        }

        [Fact]
        public void Constructor_CalculatesTotalPages_ExactDivision()
        {
            var items = new List<int> { 1, 2 };
            var list = new PaginatedList<int>(items, 10, 1, 5);
            Assert.Equal(2, list.TotalPages); // ceil(10/5) = 2
        }

        [Fact]
        public void Constructor_AddsItemsToList()
        {
            var items = new List<string> { "a", "b", "c" };
            var list = new PaginatedList<string>(items, 3, 1, 3);
            Assert.Equal(3, list.Count);
            Assert.Contains("a", list);
            Assert.Contains("b", list);
            Assert.Contains("c", list);
        }

        [Fact]
        public void HasPreviousPage_ReturnsFalse_WhenOnFirstPage()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 5, 1, 3);
            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_ReturnsTrue_WhenNotOnFirstPage()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 5, 2, 3);
            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_ReturnsTrue_WhenNotOnLastPage()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 3);
            Assert.True(list.HasNextPage); // totalPages = 4, page 1 < 4
        }

        [Fact]
        public void HasNextPage_ReturnsFalse_WhenOnLastPage()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 4, 3);
            Assert.False(list.HasNextPage); // totalPages = 4, page 4 is not < 4
        }

        [Fact]
        public void HasNextPage_ReturnsFalse_WhenSinglePage()
        {
            var list = new PaginatedList<int>(new List<int> { 1 }, 1, 1, 10);
            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();
            var result = PaginatedList<int>.Create(source, 2, 5);

            Assert.Equal(2, result.PageIndex);
            Assert.Equal(4, result.TotalPages);
            Assert.Equal(5, result.Count);
            Assert.Equal(6, result[0]); // items 6-10 on page 2
            Assert.Equal(10, result[4]);
        }

        [Fact]
        public void Create_FirstPage_ReturnsFirstItems()
        {
            var source = Enumerable.Range(1, 15).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Equal(1, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
            Assert.Equal(5, result.Count);
            Assert.Equal(1, result[0]);
        }

        [Fact]
        public void Create_LastPage_ReturnRemainingItems()
        {
            var source = Enumerable.Range(1, 12).AsQueryable();
            var result = PaginatedList<int>.Create(source, 3, 5);

            Assert.Equal(3, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
            Assert.Equal(2, result.Count); // only 2 remaining items
            Assert.Equal(11, result[0]);
            Assert.Equal(12, result[1]);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = new List<int>().AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Empty(result);
            Assert.Equal(0, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }
    }
}

