        [Fact]
        public void DeleteConfirmed_WithImagePath_DeletesFile()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            // Create an actual file for the course
            var uploadsDir = Path.Combine(_tempDir, "Uploads", "TeachingMaterials");
            Directory.CreateDirectory(uploadsDir);
            var fileName = "test_image.jpg";
            var filePath = Path.Combine(uploadsDir, fileName);
            File.WriteAllText(filePath, "fake image data");

            var course = context.Courses.Find(1050)!;
            course.TeachingMaterialImagePath = $"/Uploads/TeachingMaterials/{fileName}";
            context.SaveChanges();

            controller.DeleteConfirmed(1050);

            Assert.False(File.Exists(filePath));
        }

        #endregion

        #region Dispose

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            using var context = TestDbContextFactory.Create();
            var controller = CreateController(context);

            var ex = Record.Exception(() => controller.Dispose());
            Assert.Null(ex);
        }

        #endregion

        #region Helpers

        private static Mock<IFormFile> CreateMockFormFile(string fileName, string contentType, long length)
        {
            var mockFile = new Mock<IFormFile>();
            var content = new byte[Math.Min(length, 1024)]; // Use small buffer for test
            var ms = new MemoryStream(content);

            mockFile.Setup(f => f.FileName).Returns(fileName);
            mockFile.Setup(f => f.ContentType).Returns(contentType);
            mockFile.Setup(f => f.Length).Returns(length);
            mockFile.Setup(f => f.OpenReadStream()).Returns(ms);
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()))
                .Callback<Stream>(stream => ms.CopyTo(stream));

            return mockFile;
        }

        #endregion
    }
}

