    {
        [Fact]
        public void Index_ReturnsViewResult()
        {
            using var context = TestDbContextFactory.Create();
            var controller = new HomeController(context);

            var result = controller.Index();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void About_ReturnsViewResult_WithEnrollmentDateGroups()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new HomeController(context);

            var result = controller.About();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(viewResult.Model);
            Assert.NotEmpty(model);
        }

        [Fact]
        public void About_GroupsStudentsByEnrollmentDate()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = new HomeController(context);

            var result = controller.About();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(viewResult.Model);
            // We have 3 students with different enrollment dates in our seeded data
            Assert.True(model.Count > 0);
            Assert.All(model, g => Assert.True(g.StudentCount > 0));
        }

        [Fact]
        public void About_ReturnsEmptyList_WhenNoStudents()
        {
            using var context = TestDbContextFactory.Create();
            var controller = new HomeController(context);

            var result = controller.About();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<EnrollmentDateGroup>>(viewResult.Model);
            Assert.Empty(model);
        }

