using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using System;
using System.IO;
using System.Linq;
using System.Net;
using System.Text;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests
    {
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;
        private readonly string _tempDir;

        public CoursesControllerTests()
        {
            _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempDir);

            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempDir);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempDir);

            _mockLogger = new Mock<ILogger<CoursesController>>();
        }

        private CoursesController CreateController(SchoolContext context)
        {
            return new CoursesController(context, _mockEnv.Object, _mockLogger.Object);
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewResult_WithCourses()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Index();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Course>>(viewResult.Model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Index_ReturnsEmptyList_WhenNoCourses()
        {
            using var context = TestDbContextFactory.Create();
            var controller = CreateController(context);

            var result = controller.Index();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Course>>(viewResult.Model);
            Assert.Empty(model);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Details(1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal(1050, model.CourseID);
            Assert.Equal("Chemistry", model.Title);
        }

        #endregion

        #region Create

        [Fact]
        public void Create_Get_ReturnsViewResult_WithEmptyCourse()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Course>(viewResult.Model);
        }

        [Fact]
        public void Create_Post_ValidCourse_RedirectsToIndex()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            var result = controller.Create(course, null!);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Create_Post_ValidCourse_AddsToDatabase()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            controller.Create(course, null!);

            Assert.Equal(3, context.Courses.Count());
            Assert.NotNull(context.Courses.Find(9999));
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);
            controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 9999 };

            var result = controller.Create(course, null!);

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Create_Post_WithValidImage_UploadsFile()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = CreateMockFormFile("test.jpg", "image/jpeg", 1024);

            var result = controller.Create(course, mockFile.Object);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            var savedCourse = context.Courses.Find(9999);
            Assert.NotNull(savedCourse);
            Assert.StartsWith("/Uploads/TeachingMaterials/", savedCourse!.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_Post_WithInvalidFileExtension_ReturnsViewWithError()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = CreateMockFormFile("test.exe", "application/octet-stream", 1024);

            var result = controller.Create(course, mockFile.Object);

            Assert.IsType<ViewResult>(result);
            Assert.True(controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_WithOversizedFile_ReturnsViewWithError()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = CreateMockFormFile("test.jpg", "image/jpeg", 6 * 1024 * 1024); // 6MB

            var result = controller.Create(course, mockFile.Object);

            Assert.IsType<ViewResult>(result);
            Assert.True(controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Theory]
        [InlineData(".jpg")]
        [InlineData(".jpeg")]
        [InlineData(".png")]
        [InlineData(".gif")]
        [InlineData(".bmp")]
        public void Create_Post_AllowedExtensions_AreAccepted(string extension)
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);
            var course = new Course
            {
                CourseID = 9999 + extension.GetHashCode() % 1000,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = 1
            };

            var mockFile = CreateMockFormFile($"test{extension}", "image/jpeg", 1024);

            var result = controller.Create(course, mockFile.Object);

            Assert.IsType<RedirectToActionResult>(result);
        }

        #endregion

        #region Edit

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithCourse()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Edit(1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal(1050, model.CourseID);
        }

        [Fact]
        public void Edit_Post_ValidCourse_RedirectsToIndex()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);
            var existing = context.Courses.Find(1050)!;
            context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var course = new Course
            {
                CourseID = 1050,
                Title = "Updated Chemistry",
                Credits = 4,
                DepartmentID = 1
            };

            var result = controller.Edit(course, null!);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);
            controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1050 };

            var result = controller.Edit(course, null!);

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Edit_Post_WithInvalidFileExtension_ReturnsViewWithError()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);
            var existing = context.Courses.Find(1050)!;
            context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };
            var mockFile = CreateMockFormFile("test.txt", "text/plain", 1024);

            var result = controller.Edit(course, mockFile.Object);

            Assert.IsType<ViewResult>(result);
            Assert.True(controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Edit_Post_WithOversizedFile_ReturnsViewWithError()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);
            var existing = context.Courses.Find(1050)!;
            context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };
            var mockFile = CreateMockFormFile("test.jpg", "image/jpeg", 6 * 1024 * 1024);

            var result = controller.Edit(course, mockFile.Object);

            Assert.IsType<ViewResult>(result);
            Assert.True(controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        #endregion

        #region Delete

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithCourse()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Delete(1050);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal(1050, model.CourseID);
        }

        [Fact]
        public void DeleteConfirmed_RemovesCourseAndRedirects()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);
            var initialCount = context.Courses.Count();

            var result = controller.DeleteConfirmed(1050);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Equal(initialCount - 1, context.Courses.Count());
        }

        [Fact]
        public void DeleteConfirmed_WithImagePath_DeletesFile()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            // Create an actual file for the course
            var uploadsDir = Path.Combine(_tempDir, "Uploads", "TeachingMaterials");
            Directory.CreateDirectory(uploadsDir);
            var fileName = "test_image.jpg";
            var filePath = Path.Combine(uploadsDir, fileName);
            File.WriteAllText(filePath, "fake image data");

            var course = context.Courses.Find(1050)!;
            course.TeachingMaterialImagePath = $"/Uploads/TeachingMaterials/{fileName}";
            context.SaveChanges();

            controller.DeleteConfirmed(1050);

            Assert.False(File.Exists(filePath));
        }

        #endregion

        #region Dispose

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            using var context = TestDbContextFactory.Create();
            var controller = CreateController(context);

            var ex = Record.Exception(() => controller.Dispose());
            Assert.Null(ex);
        }

        #endregion

        #region Helpers

        private static Mock<IFormFile> CreateMockFormFile(string fileName, string contentType, long length)
        {
            var mockFile = new Mock<IFormFile>();
            var content = new byte[Math.Min(length, 1024)]; // Use small buffer for test
            var ms = new MemoryStream(content);

            mockFile.Setup(f => f.FileName).Returns(fileName);
            mockFile.Setup(f => f.ContentType).Returns(contentType);
            mockFile.Setup(f => f.Length).Returns(length);
            mockFile.Setup(f => f.OpenReadStream()).Returns(ms);
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()))
                .Callback<Stream>(stream => ms.CopyTo(stream));

            return mockFile;
        }

        #endregion
    }
