using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests
    {
        private InstructorsController CreateController(SchoolContext context)
        {
            return new InstructorsController(context);
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewResult_WithInstructorIndexData()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Index(null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.NotNull(model.Instructors);
        }

        [Fact]
        public void Index_ReturnsAllInstructors()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Index(null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_SetsCourses()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);
            var instructorId = context.Instructors.First().ID;

            var result = controller.Index(instructorId, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.NotNull(model.Courses);
        }

        [Fact]
        public void Index_WithInstructorId_SetsViewBagInstructorID()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);
            var instructorId = context.Instructors.First().ID;

            controller.Index(instructorId, null);

            Assert.Equal(instructorId, controller.ViewBag.InstructorID);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);
            var instructorId = context.Instructors.First().ID;

            var result = controller.Details(instructorId);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal(instructorId, model.ID);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        #endregion

        #region Create

        [Fact]
        public void Create_Get_ReturnsViewResult_WithInstructor()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Empty(model.CourseAssignments);
        }

        [Fact]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = new DateTime(2020, 1, 15)
            };

            var result = controller.Create(instructor, null!);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Create_Post_ValidInstructor_AddsToDatabase()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = new DateTime(2020, 1, 15)
            };

            controller.Create(instructor, null!);

            Assert.Equal(3, context.Instructors.Count());
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_AssignsCourses()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = new DateTime(2020, 1, 15)
            };
            var selectedCourses = new[] { "1050", "4022" };

            controller.Create(instructor, selectedCourses);

            var created = context.Instructors.OrderByDescending(i => i.ID).First();
            Assert.Equal(2, created.CourseAssignments.Count);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);
            controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor();

            var result = controller.Create(instructor, null!);

            Assert.IsType<ViewResult>(result);
        }

        #endregion

        #region Edit

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithInstructor()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);
            var instructorId = context.Instructors.First().ID;

            var result = controller.Edit(instructorId);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal(instructorId, model.ID);
        }

        #endregion

        #region Delete

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal((int)HttpStatusCode.BadRequest, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            var result = controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithInstructor()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);
            var instructorId = context.Instructors.First().ID;

            var result = controller.Delete(instructorId);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal(instructorId, model.ID);
        }

        [Fact]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);
            // Use instructor2 (ID=2) who has no office assignment
            var instructorId = context.Instructors.First(i => i.LastName == "Fakhouri").ID;
            var initialCount = context.Instructors.Count();

            var result = controller.DeleteConfirmed(instructorId);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Equal(initialCount - 1, context.Instructors.Count());
        }

        [Fact]
        public void DeleteConfirmed_ClearsDepartmentAdministrator()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            var controller = CreateController(context);

            // Set instructor as department administrator
            var instructor = context.Instructors.First();
            var department = context.Departments.First();
            department.InstructorID = instructor.ID;
            context.SaveChanges();

            controller.DeleteConfirmed(instructor.ID);

            var updatedDept = context.Departments.Find(department.DepartmentID)!;
            Assert.Null(updatedDept.InstructorID);
        }

        #endregion
    }
}

