using ContosoUniversity.Controllers;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests
    {
        [Fact]
        public void Index_ReturnsViewResult()
        {
            using var context = TestDbContextFactory.Create();
            var controller = new NotificationsController(context);

            var result = controller.Index();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void GetNotifications_ReturnsJsonResult()
        {
            using var context = TestDbContextFactory.Create();
            var controller = new NotificationsController(context);

            var result = controller.GetNotifications();

            Assert.IsType<JsonResult>(result);
        }

        [Fact]
        public void GetNotifications_ReturnsSuccessTrue()
        {
            using var context = TestDbContextFactory.Create();
            var controller = new NotificationsController(context);

            var result = controller.GetNotifications();

            var jsonResult = Assert.IsType<JsonResult>(result);
            Assert.NotNull(jsonResult.Value);
            var value = jsonResult.Value!;
            var successProp = value.GetType().GetProperty("success");
            Assert.NotNull(successProp);
            Assert.True((bool)successProp!.GetValue(value)!);
        }

        [Fact]
        public void MarkAsRead_ReturnsJsonResult_WithSuccess()
        {
            using var context = TestDbContextFactory.Create();
            var controller = new NotificationsController(context);

            var result = controller.MarkAsRead(1);

            var jsonResult = Assert.IsType<JsonResult>(result);
            Assert.NotNull(jsonResult.Value);
            var value = jsonResult.Value!;
            var successProp = value.GetType().GetProperty("success");
            Assert.NotNull(successProp);
            Assert.True((bool)successProp!.GetValue(value)!);
        }

        [Fact]
        public void GetNotifications_ReturnsNotificationsAfterSend()
        {
            using var context = TestDbContextFactory.CreateSeeded();
            // Use the StudentsController to send a notification, then read via NotificationsController
            var studentsController = new StudentsController(context);
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new System.DateTime(2020, 9, 1)
            };
            studentsController.Create(student);

            var notifController = new NotificationsController(context);
            var result = notifController.GetNotifications();

            var jsonResult = Assert.IsType<JsonResult>(result);
            Assert.NotNull(jsonResult.Value);
            var value = jsonResult.Value!;
            var countProp = value.GetType().GetProperty("count");
            Assert.NotNull(countProp);
            var count = (int)countProp!.GetValue(value)!;
            Assert.True(count >= 1);
        }
    }
}

