using ContosoUniversity.Data;
using ContosoUniversity.Tests.Helpers;
using System.Linq;

namespace ContosoUniversity.Tests.Data
{
    public class DbInitializerTests
    {
        [Fact]
        public void Initialize_SeedsStudents()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.Equal(8, context.Students.Count());
        }

        [Fact]
        public void Initialize_SeedsInstructors()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.Equal(5, context.Instructors.Count());
        }

        [Fact]
        public void Initialize_SeedsDepartments()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.Equal(4, context.Departments.Count());
        }

        [Fact]
        public void Initialize_SeedsCourses()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.Equal(7, context.Courses.Count());
        }

        [Fact]
        public void Initialize_SeedsOfficeAssignments()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.Equal(3, context.OfficeAssignments.Count());
        }

        [Fact]
        public void Initialize_SeedsCourseAssignments()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.Equal(8, context.CourseAssignments.Count());
        }

        [Fact]
        public void Initialize_SeedsEnrollments()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            Assert.Equal(11, context.Enrollments.Count());
        }

        [Fact]
        public void Initialize_DoesNotSeedTwice()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);
            DbInitializer.Initialize(context);

            Assert.Equal(8, context.Students.Count());
        }

        [Fact]
        public void Initialize_SkipsWhenStudentsExist()
        {
            using var context = TestDbContextFactory.CreateSeeded();

            // Call Initialize on already-seeded context
            DbInitializer.Initialize(context);

            // Should still have original 3 students, not 8
            Assert.Equal(3, context.Students.Count());
        }

        [Fact]
        public void Initialize_StudentNamesAreCorrect()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            var studentNames = context.Students.Select(s => s.LastName).OrderBy(n => n).ToList();
            Assert.Contains("Alexander", studentNames);
            Assert.Contains("Alonso", studentNames);
            Assert.Contains("Anand", studentNames);
            Assert.Contains("Barzdukas", studentNames);
            Assert.Contains("Li", studentNames);
            Assert.Contains("Justice", studentNames);
            Assert.Contains("Norman", studentNames);
            Assert.Contains("Olivetto", studentNames);
        }

        [Fact]
        public void Initialize_DepartmentNamesAreCorrect()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            var deptNames = context.Departments.Select(d => d.Name).OrderBy(n => n).ToList();
            Assert.Equal(new[] { "Economics", "Engineering", "English", "Mathematics" }, deptNames);
        }

        [Fact]
        public void Initialize_EnrollmentsHaveGrades()
        {
            using var context = TestDbContextFactory.Create();

            DbInitializer.Initialize(context);

            var withGrades = context.Enrollments.Count(e => e.Grade != null);
            var withoutGrades = context.Enrollments.Count(e => e.Grade == null);
            Assert.True(withGrades > 0);
            Assert.True(withoutGrades > 0);
        }
    }
}

