using System.Linq;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests
    {
        [Fact]
        public void CanCreateContext()
        {
            using var context = TestDbContextFactory.Create();
            Assert.NotNull(context);
        }

        [Fact]
        public void Context_HasStudentsDbSet()
        {
            using var context = TestDbContextFactory.Create();
            Assert.NotNull(context.Students);
        }

        [Fact]
        public void Context_HasInstructorsDbSet()
        {
            using var context = TestDbContextFactory.Create();
            Assert.NotNull(context.Instructors);
        }

        [Fact]
        public void Context_HasCoursesDbSet()
        {
            using var context = TestDbContextFactory.Create();
            Assert.NotNull(context.Courses);
        }

        [Fact]
        public void Context_HasDepartmentsDbSet()
        {
            using var context = TestDbContextFactory.Create();
            Assert.NotNull(context.Departments);
        }

        [Fact]
        public void Context_HasEnrollmentsDbSet()
        {
            using var context = TestDbContextFactory.Create();
            Assert.NotNull(context.Enrollments);
        }

        [Fact]
        public void Context_HasCourseAssignmentsDbSet()
        {
            using var context = TestDbContextFactory.Create();
            Assert.NotNull(context.CourseAssignments);
        }

        [Fact]
        public void Context_HasOfficeAssignmentsDbSet()
        {
            using var context = TestDbContextFactory.Create();
            Assert.NotNull(context.OfficeAssignments);
        }

        [Fact]
        public void Context_HasNotificationsDbSet()
        {
            using var context = TestDbContextFactory.Create();
            Assert.NotNull(context.Notifications);
        }

        [Fact]
        public void Context_HasPeopleDbSet()
        {
            using var context = TestDbContextFactory.Create();
            Assert.NotNull(context.People);
        }

        [Fact]
        public void CanAddAndRetrieveStudent()
        {
            using var context = TestDbContextFactory.Create();
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };

            context.Students.Add(student);
            context.SaveChanges();

            var retrieved = context.Students.First();
            Assert.Equal("Test", retrieved.FirstMidName);
            Assert.Equal("Student", retrieved.LastName);
        }

        [Fact]
        public void CanAddAndRetrieveInstructor()
        {
            using var context = TestDbContextFactory.Create();
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Instructor",
                HireDate = new DateTime(2020, 1, 15)
            };

            context.Instructors.Add(instructor);
            context.SaveChanges();

            var retrieved = context.Instructors.First();
            Assert.Equal("Test", retrieved.FirstMidName);
        }

        [Fact]
        public void CourseAssignment_HasCompositeKey()
        {
            using var context = TestDbContextFactory.CreateSeeded();

            var ca = context.CourseAssignments.First();
            Assert.True(ca.CourseID > 0);
            Assert.True(ca.InstructorID > 0);
        }

        [Fact]
        public void Student_InheritsFromPerson_ViaTPH()
        {
            using var context = TestDbContextFactory.Create();
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };
            context.Students.Add(student);
            context.SaveChanges();

            // Should be queryable from People as well
            var person = context.People.First();
            Assert.IsType<Student>(person);
        }

        [Fact]
        public void Instructor_InheritsFromPerson_ViaTPH()
        {
            using var context = TestDbContextFactory.Create();
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Instructor",
                HireDate = new DateTime(2020, 1, 15)
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            var person = context.People.First();
            Assert.IsType<Instructor>(person);
        }

        [Fact]
        public void CanAddNotification()
        {
            using var context = TestDbContextFactory.Create();
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test notification",
                CreatedAt = DateTime.Now,
                CreatedBy = "admin",
                IsRead = false
            };

            context.Notifications.Add(notification);
            context.SaveChanges();

            Assert.Single(context.Notifications);
        }
    }
}

